import { useEffect, useState } from "react";
import { C } from "../constants";
import TransactionDetailsModal from "./TransactionDetailsModal";
import { inputStyle, selectStyle } from "../styles";

export default function TransactionsTab({
  categories,
  transactions,
  uncategorizedTransactions,
  showUncategorizedSection,
  uncategorizedAssignments,
  uncategorizedSaveSuccess,
  selectedTransactionIds,
  spentByCategory,
  formatCurrency,
  getCategoryById,
  importError,
  isImportDragActive,
  mostRecentImportedTransactionLabel,
  fileInputRef,
  showTxForm,
  newTx,
  autocomplete,
  nameInputRef,
  onOpenImportPicker,
  onImportDragOver,
  onImportDragLeave,
  onImportDrop,
  onOpenTxForm,
  onCloseTxForm,
  onNameChange,
  onPickSuggestion,
  onNewTransactionChange,
  onAddTransaction,
  onDeleteTransaction,
  onToggleTransactionSelection,
  onToggleAllTransactions,
  onDeleteSelectedTransactions,
  onUpdateTransactionCategory,
  onAssignSelectedTransactions,
  onUncategorizedAssignmentChange,
  onSaveUncategorizedAssignments,
}) {
  const selectedCount = selectedTransactionIds.length;
  const allSelected = transactions.length > 0 && selectedCount === transactions.length;
  const allUncategorizedAssigned =
    uncategorizedTransactions.length > 0 &&
    uncategorizedTransactions.every((transaction) => uncategorizedAssignments[transaction.id]);
  const [activeTransaction, setActiveTransaction] = useState(null);
  const [activeCategoryId, setActiveCategoryId] = useState("");
  const [bulkCategoryId, setBulkCategoryId] = useState("__none__");

  useEffect(() => {
    if (!activeTransaction) return;

    const latestTransaction = transactions.find(
      (transaction) => transaction.id === activeTransaction.id,
    );

    if (!latestTransaction) {
      setActiveTransaction(null);
      setActiveCategoryId("");
      return;
    }

    setActiveTransaction(latestTransaction);
    setActiveCategoryId(latestTransaction.categoryId?.toString() || "");
  }, [activeTransaction, transactions]);

  const openTransactionDetails = (transaction) => {
    setActiveTransaction(transaction);
    setActiveCategoryId(transaction.categoryId?.toString() || "");
  };

  const closeTransactionDetails = () => {
    setActiveTransaction(null);
    setActiveCategoryId("");
  };

  const saveTransactionCategory = () => {
    if (!activeTransaction) return;
    onUpdateTransactionCategory(activeTransaction.id, activeCategoryId);
    closeTransactionDetails();
  };

  const assignSelectedTransactions = () => {
    if (selectedCount === 0 || bulkCategoryId === "__none__") return;

    onAssignSelectedTransactions(bulkCategoryId);
    setBulkCategoryId("__none__");
  };

  return (
    <div className="fade-up">
      {activeTransaction && (
        <TransactionDetailsModal
          transaction={activeTransaction}
          categories={categories}
          categoryId={activeCategoryId}
          onCategoryChange={setActiveCategoryId}
          onSave={saveTransactionCategory}
          onClose={closeTransactionDetails}
        />
      )}

      {showUncategorizedSection && (
        <div
          className="fade-up"
          style={{
            position: "relative",
            marginBottom: "20px",
            background: C.surface,
            border: `1.5px solid ${uncategorizedSaveSuccess ? C.green : C.blueMid}`,
            borderRadius: "18px",
            padding: "18px",
            boxShadow: uncategorizedSaveSuccess
              ? "0 14px 30px rgba(22,163,74,0.18)"
              : "0 8px 24px rgba(30,80,212,0.1)",
            overflow: "hidden",
          }}
        >
          <div style={{ marginBottom: "14px" }}>
            <div
              style={{
                fontSize: "12px",
                color: uncategorizedSaveSuccess ? C.green : C.textLight,
                letterSpacing: "2px",
                marginBottom: "6px",
                fontWeight: 700,
              }}
            >
              UNCATEGORIZED REVIEW
            </div>
            <div style={{ fontSize: "20px", fontWeight: 700, color: C.text }}>
              Assign categories to these transactions
            </div>
            <div style={{ fontSize: "13px", color: C.textMid, marginTop: "4px" }}>
              Choose a category for each uncategorized transaction, then save them all at once.
            </div>
          </div>

          {!uncategorizedSaveSuccess && (
            <>
              <div style={{ display: "grid", gap: "10px" }}>
                {uncategorizedTransactions.map((transaction) => (
                  <div
                    key={transaction.id}
                    style={{
                      display: "grid",
                      gridTemplateColumns: "minmax(0, 1fr) 180px",
                      gap: "12px",
                      alignItems: "center",
                      padding: "12px 14px",
                      borderRadius: "12px",
                      background: C.surfaceAlt,
                      border: `1px solid ${C.border}`,
                    }}
                  >
                    <div style={{ minWidth: 0 }}>
                      <div
                        style={{
                          fontSize: "15px",
                          fontWeight: 700,
                          color: C.text,
                          overflow: "hidden",
                          textOverflow: "ellipsis",
                          whiteSpace: "nowrap",
                        }}
                      >
                        {transaction.name}
                      </div>
                      <div style={{ fontSize: "12px", color: C.textMid, marginTop: "3px" }}>
                        {transaction.date} | -${formatCurrency(parseFloat(transaction.amount))}
                      </div>
                    </div>

                    <select
                      value={uncategorizedAssignments[transaction.id] || ""}
                      onChange={(event) =>
                        onUncategorizedAssignmentChange(transaction.id, event.target.value)
                      }
                      style={selectStyle}
                    >
                      <option value="">Choose category</option>
                      {categories.map((category) => (
                        <option key={category.id} value={category.id}>
                          {category.name}
                        </option>
                      ))}
                    </select>
                  </div>
                ))}
              </div>

              <div style={{ marginTop: "14px", display: "flex", justifyContent: "flex-end" }}>
                <button
                  onClick={onSaveUncategorizedAssignments}
                  disabled={!allUncategorizedAssigned}
                  style={{
                    background: allUncategorizedAssigned ? C.blue : C.surfaceAlt,
                    border: "none",
                    color: allUncategorizedAssigned ? C.white : C.textLight,
                    padding: "12px 18px",
                    borderRadius: "10px",
                    cursor: allUncategorizedAssigned ? "pointer" : "default",
                    fontSize: "14px",
                    fontWeight: 700,
                  }}
                >
                  Save
                </button>
              </div>
            </>
          )}

          {uncategorizedSaveSuccess && (
            <div
              style={{
                display: "grid",
                placeItems: "center",
                minHeight: "220px",
                textAlign: "center",
                color: C.green,
              }}
            >
              <div>
                <div style={{ display: "flex", justifyContent: "center" }}>
                  <svg width="96" height="96" viewBox="0 0 96 96" fill="none" aria-hidden="true">
                    <circle cx="48" cy="48" r="44" fill={C.greenLight} />
                    <path
                      d="M28 49L41 62L68 35"
                      stroke={C.green}
                      strokeWidth="8"
                      strokeLinecap="round"
                      strokeLinejoin="round"
                    />
                  </svg>
                </div>
                <div style={{ fontSize: "18px", fontWeight: 700, marginTop: "10px" }}>
                  Uncategorized transactions saved
                </div>
              </div>
            </div>
          )}
        </div>
      )}

      <div style={{ display: "flex", gap: "10px", marginBottom: "16px", alignItems: "stretch" }}>
        <button
          className="import-btn"
          onClick={onOpenImportPicker}
          onDragOver={onImportDragOver}
          onDragLeave={onImportDragLeave}
          onDrop={onImportDrop}
          style={{
            flex: 1,
            display: "flex",
            alignItems: "center",
            justifyContent: "center",
            gap: "10px",
            background: isImportDragActive ? C.blueLight : C.surface,
            border: `1.5px dashed ${isImportDragActive ? C.blue : C.blueMid}`,
            color: isImportDragActive ? C.text : C.textMid,
            padding: "14px 20px",
            borderRadius: "10px",
            cursor: "pointer",
            fontSize: "14px",
            fontWeight: 600,
            transition: "all 0.15s",
            boxShadow: isImportDragActive
              ? "0 10px 28px rgba(30,80,212,0.16)"
              : "0 2px 8px rgba(30,80,212,0.06)",
          }}
        >
          <span style={{ fontSize: "14px", fontWeight: 800, letterSpacing: "0.08em" }}>XLS</span>
          <div style={{ textAlign: "left" }}>
            <div style={{ color: C.text, fontWeight: 700 }}>
              {isImportDragActive ? "Drop file to import" : "Import from Excel"}
            </div>
            <div style={{ fontSize: "12px", color: C.textLight, marginTop: "1px" }}>
              Drag and drop or click to upload your bank&apos;s .xlsx export
            </div>
          </div>
        </button>
      </div>

      <input
        ref={fileInputRef}
        type="file"
        accept=".xlsx,.xls,.csv"
        onChange={onOpenImportPicker}
        style={{ display: "none" }}
      />

      {importError && (
        <div
          style={{
            background: C.redLight,
            border: "1px solid #fecaca",
            borderRadius: "8px",
            padding: "12px 16px",
            fontSize: "13px",
            color: C.red,
            marginBottom: "14px",
            fontWeight: 500,
          }}
        >
          {importError}
        </div>
      )}

      {showTxForm ? (
        <div
          className="slide-down"
          style={{
            background: C.surface,
            border: `1.5px solid ${C.border}`,
            borderRadius: "14px",
            padding: "20px",
            marginBottom: "20px",
            boxShadow: "0 4px 16px rgba(30,80,212,0.1)",
          }}
        >
          <div
            style={{
              fontSize: "12px",
              color: C.textLight,
              letterSpacing: "2px",
              marginBottom: "16px",
              fontWeight: 600,
            }}
          >
            NEW TRANSACTION
          </div>
          <div style={{ display: "flex", flexDirection: "column", gap: "12px" }}>
            <div style={{ position: "relative" }}>
              <input
                ref={nameInputRef}
                placeholder="What was this for?"
                value={newTx.name}
                onChange={(event) => onNameChange(event.target.value)}
                onKeyDown={(event) => event.key === "Enter" && onAddTransaction()}
                style={inputStyle}
              />
              {autocomplete.length > 0 && (
                <div
                  className="slide-down"
                  style={{
                    position: "absolute",
                    top: "calc(100% + 4px)",
                    left: 0,
                    right: 0,
                    background: C.surface,
                    border: `1.5px solid ${C.border}`,
                    borderRadius: "8px",
                    overflow: "hidden",
                    zIndex: 20,
